	to := strings.TrimSpace(req.ToAccountId)
	if from == "" || to == "" {
		return nil, status.Error(codes.InvalidArgument, "from_account_id and to_account_id are required")
	}
	if from == to {
		return nil, status.Error(codes.InvalidArgument, "from_account_id and to_account_id must differ")
	}
	amt := req.Amount
	if amt == nil {
		return nil, status.Error(codes.InvalidArgument, "amount is required")
	}
	currency := strings.ToUpper(strings.TrimSpace(amt.Currency))
	if currency == "" {
		return nil, status.Error(codes.InvalidArgument, "amount.currency is required")
	}
	if amt.Units < 0 || amt.Nanos < 0 {
		return nil, status.Error(codes.InvalidArgument, "amount must be non-negative")
	}
	if amt.Nanos >= 1_000_000_000 {
		return nil, status.Error(codes.InvalidArgument, "amount.nanos must be < 1e9")
	}

