func moneyToNanos(m *transactionsv1.Money) (int64, error) {
	if m == nil {
		return 0, errors.New("money is nil")
	}
	if m.Units < 0 || m.Nanos < 0 || m.Nanos >= 1_000_000_000 {
		return 0, errors.New("invalid money")
	}
	unitsNanos := m.Units * 1_000_000_000
	if (m.Units > 0 && unitsNanos < 0) || (m.Units < 0 && unitsNanos > 0) {
		return 0, errors.New("money overflow")
	}
	sum := unitsNanos + int64(m.Nanos)
	if (unitsNanos > 0 && int64(m.Nanos) > 0 && sum < 0) || (unitsNanos < 0 && int64(m.Nanos) < 0 && sum > 0) {
		return 0, errors.New("money overflow")
	}
	return sum, nil
}

func nanosToMoney(currency string, nanos int64) (*transactionsv1.Money, error) {
	if nanos < 0 {
		return nil, errors.New("negative nanos")
	}
	units := nanos / 1_000_000_000
	rem := nanos % 1_000_000_000
	return &transactionsv1.Money{
		Currency: currency,
		Units:    units,
		Nanos:    int32(rem),
	}, nil
}

func randSuffix(n int) string {
	const alpha = "abcdefghijklmnopqrstuvwxyz0123456789"
	x := time.Now().UnixNano()
	var b strings.Builder
	b.Grow(n)
	for i := 0; i < n; i++ {
		x ^= x << 13
		x ^= x >> 7
		x ^= x << 17
		b.WriteByte(alpha[int(x)%len(alpha)])
	}
	return b.String()
}

